Code.Terraform:
```hcl
resource "aws_cloudfront_distribution" "<example_resource_name>" {
  enabled = true

  origin {
    domain_name = "<example_origin_domain>"
    origin_id   = "origin1"
    s3_origin_config {}
  }

  default_cache_behavior {
    target_origin_id       = "origin1"
    viewer_protocol_policy = "redirect-to-https"
    forwarded_values { query_string = false }
  }

  aliases = ["<example_domain>"]  # 重要：証明書でカバーされるCNAMEを追加

  viewer_certificate {
    acm_certificate_arn = "<example_certificate_arn>"  # 重要：カスタムACM証明書（us-east-1内）
    ssl_support_method  = "sni-only"                    # 重要：ACM証明書を使用する場合に必要
  }
}
```
